 1	import { type FC, useRef } from 'react';
 2	import { DateTime } from 'luxon';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import PlanCutoverMigrationModal from 'src/plans/actions/components/CutoverModal/PlanCutoverMigrationModal';
 5	import { usePlanMigration } from 'src/plans/hooks/usePlanMigration';
 6	
 7	import type { V1beta1Plan } from '@kubev2v/types';
 8	import { Button, type ButtonVariant, Tooltip } from '@patternfly/react-core';
 9	import { CalendarAltIcon } from '@patternfly/react-icons';
10	import { getPlanIsWarm } from '@utils/crds/plans/selectors';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import { isPlanArchived, isPlanExecuting } from '../details/components/PlanStatus/utils/utils';
14	
15	type PlanEditCutoverButtonProps = {
16	  plan: V1beta1Plan;
17	  variant: ButtonVariant;
18	};
19	
20	const PlanEditCutoverButton: FC<PlanEditCutoverButtonProps> = ({ plan, variant }) => {
21	  const { t } = useForkliftTranslation();
22	  const { showModal } = useModal();
23	  const cutoverButtonRef = useRef<HTMLButtonElement>(null);
24	  const [migration] = usePlanMigration(plan);
25	
26	  if (!getPlanIsWarm(plan) || !isPlanExecuting(plan) || isPlanArchived(plan)) {
27	    return null;
28	  }
29	
30	  const cutoverDateTime = migration?.spec?.cutover
31	    ? DateTime.fromISO(migration.spec.cutover).toLocaleString(DateTime.DATETIME_FULL)
32	    : '';
33	
34	  return (
35	    <>
36	      <Button
37	        ref={cutoverButtonRef}
38	        isInline
39	        variant={variant}
40	        onClick={() => {
41	          showModal(<PlanCutoverMigrationModal plan={plan} />);
42	        }}
43	        icon={<CalendarAltIcon />}
44	        iconPosition="left"
45	      >
46	        {cutoverDateTime ? t('Edit cutover') : t('Schedule cutover')}
47	      </Button>
48	      {cutoverDateTime ? <Tooltip content={cutoverDateTime} triggerRef={cutoverButtonRef} /> : null}
49	    </>
50	  );
51	};
52	
53	export default PlanEditCutoverButton;

